
-- Trade System Tables
-- Drop existing if needed
DROP TABLE IF EXISTS trade_prices CASCADE;
DROP TABLE IF EXISTS trade_terminals CASCADE;
DROP TABLE IF EXISTS trade_commodities CASCADE;
DROP TABLE IF EXISTS trade_star_systems CASCADE;
DROP TABLE IF EXISTS trade_planets CASCADE;

-- Star Systems
CREATE TABLE trade_star_systems (
  id INT PRIMARY KEY,
  name TEXT NOT NULL,
  code TEXT,
  is_available INT DEFAULT 1,
  date_added BIGINT,
  date_modified BIGINT
);

-- Planets
CREATE TABLE trade_planets (
  id INT PRIMARY KEY,
  id_star_system INT REFERENCES trade_star_systems(id),
  name TEXT NOT NULL,
  code TEXT,
  is_available INT DEFAULT 1,
  date_added BIGINT,
  date_modified BIGINT
);

-- Commodities
CREATE TABLE trade_commodities (
  id INT PRIMARY KEY,
  id_parent INT,
  name TEXT NOT NULL,
  code TEXT,
  kind TEXT,
  weight_scu NUMERIC(6,2),
  price_buy NUMERIC(12,2) DEFAULT 0,
  price_sell NUMERIC(12,2) DEFAULT 0,
  is_available INT DEFAULT 1,
  is_mineral INT DEFAULT 0,
  is_raw INT DEFAULT 0,
  is_refined INT DEFAULT 0,
  is_harvestable INT DEFAULT 0,
  is_buyable INT DEFAULT 0,
  is_sellable INT DEFAULT 0,
  is_illegal INT DEFAULT 0,
  is_volatile_qt INT DEFAULT 0,
  wiki TEXT,
  date_added BIGINT,
  date_modified BIGINT
);

-- Terminals (trade locations)
CREATE TABLE trade_terminals (
  id INT PRIMARY KEY,
  id_star_system INT REFERENCES trade_star_systems(id),
  id_planet INT,
  id_moon INT DEFAULT 0,
  id_space_station INT DEFAULT 0,
  id_outpost INT DEFAULT 0,
  id_city INT DEFAULT 0,
  id_faction INT DEFAULT 0,
  name TEXT NOT NULL,
  nickname TEXT,
  code TEXT,
  type TEXT DEFAULT 'commodity',
  is_available INT DEFAULT 1,
  is_visible INT DEFAULT 1,
  is_habitation INT DEFAULT 0,
  is_refinery INT DEFAULT 0,
  is_cargo_center INT DEFAULT 0,
  is_medical INT DEFAULT 0,
  is_food INT DEFAULT 0,
  is_refuel INT DEFAULT 0,
  is_repair INT DEFAULT 0,
  is_nqa INT DEFAULT 0,
  is_auto_load INT DEFAULT 0,
  has_loading_dock INT DEFAULT 0,
  has_freight_elevator INT DEFAULT 0,
  max_container_size INT DEFAULT 32,
  star_system_name TEXT,
  planet_name TEXT,
  orbit_name TEXT,
  moon_name TEXT,
  space_station_name TEXT,
  outpost_name TEXT,
  city_name TEXT,
  faction_name TEXT,
  company_name TEXT,
  date_added BIGINT,
  date_modified BIGINT
);

-- Commodity Prices per Terminal
CREATE TABLE trade_prices (
  id INT PRIMARY KEY,
  id_commodity INT REFERENCES trade_commodities(id),
  id_terminal INT REFERENCES trade_terminals(id),
  price_buy NUMERIC(12,2) DEFAULT 0,
  price_buy_avg NUMERIC(12,2) DEFAULT 0,
  price_sell NUMERIC(12,2) DEFAULT 0,
  price_sell_avg NUMERIC(12,2) DEFAULT 0,
  scu_buy INT DEFAULT 0,
  scu_buy_avg INT DEFAULT 0,
  scu_sell_stock INT DEFAULT 0,
  scu_sell_stock_avg INT DEFAULT 0,
  scu_sell INT DEFAULT 0,
  scu_sell_avg INT DEFAULT 0,
  status_buy INT DEFAULT 0,
  status_sell INT DEFAULT 0,
  container_sizes TEXT,
  commodity_name TEXT,
  terminal_name TEXT,
  date_added BIGINT,
  date_modified BIGINT
);

-- Indexes
CREATE INDEX idx_trade_prices_commodity ON trade_prices(id_commodity);
CREATE INDEX idx_trade_prices_terminal ON trade_prices(id_terminal);
CREATE INDEX idx_trade_terminals_system ON trade_terminals(id_star_system);
CREATE INDEX idx_trade_commodities_kind ON trade_commodities(kind);

